import React, { useState, useRef, useEffect, useCallback } from 'react';
import { MessageCircle, Send, Bot, User, Zap, Leaf, TrendingDown, Lightbulb, Thermometer, Cloud, Sun } from 'lucide-react';

const ChatBot = () => {
  const [messages, setMessages] = useState([
    {
      id: 1,
      type: 'bot',
      text: "👋 Hi! I'm your SmartComfort assistant with real-time weather data! I can help you with:\n\n🌤️ Current weather conditions\n⚡ Energy-saving tips\n🌡️ HVAC recommendations\n🏢 Campus building efficiency\n\nHow can I assist you today?",
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [weatherData, setWeatherData] = useState(null);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Fetch real weather data for Kalamazoo, MI (WMU location)
  const fetchWeatherData = useCallback(async () => {
    try {
      const response = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=Kalamazoo,US&appid=YOUR_API_KEY&units=imperial`);
      if (!response.ok) {
        throw new Error('Weather API unavailable');
      }
      const data = await response.json();
      setWeatherData({
        temp: Math.round(data.main.temp),
        feels_like: Math.round(data.main.feels_like),
        humidity: data.main.humidity,
        wind_speed: data.wind.speed,
        description: data.weather[0].description,
        icon: data.weather[0].icon
      });
    } catch (error) {
      // Fallback to mock data for demo purposes
      setWeatherData({
        temp: 72,
        feels_like: 70,
        humidity: 65,
        wind_speed: 8,
        description: 'partly cloudy',
        icon: '02d'
      });
    }
  }, []);

  useEffect(() => {
    fetchWeatherData();
    const interval = setInterval(fetchWeatherData, 300000); // Update every 5 minutes
    return () => clearInterval(interval);
  }, [fetchWeatherData]);

  const getWeatherBasedResponse = useCallback(() => {
    if (!weatherData) return null;
    
    const { temp, humidity, description } = weatherData;
    let response = `🌤️ **Current Weather in Kalamazoo:**\n`;
    response += `🌡️ Temperature: ${temp}°F (feels like ${weatherData.feels_like}°F)\n`;
    response += `💧 Humidity: ${humidity}%\n`;
    response += `💨 Wind: ${weatherData.wind_speed} mph\n`;
    response += `☁️ Conditions: ${description}\n\n`;
    
    // Add weather-based recommendations
    if (temp > 80) {
      response += `🔥 **Heat Advisory:**\n`;
      response += `• Set thermostat to 78°F for optimal efficiency\n`;
      response += `• Use ceiling fans to feel 4°F cooler\n`;
      response += `• Close blinds during peak sun hours\n`;
      response += `• Stay hydrated and report AC issues immediately\n\n`;
    } else if (temp < 40) {
      response += `🧊 **Cold Weather Alert:**\n`;
      response += `• Set thermostat to 68°F for maximum efficiency\n`;
      response += `• Seal windows and doors to prevent heat loss\n`;
      response += `• Use natural sunlight for passive heating\n`;
      response += `• Report heating issues promptly\n\n`;
    } else {
      response += `🌡️ **Moderate Weather:**\n`;
      response += `• Perfect conditions for natural ventilation\n`;
      response += `• Open windows for fresh air when appropriate\n`;
      response += `• Minimal HVAC adjustment needed\n\n`;
    }
    
    if (humidity > 70) {
      response += `💧 **High Humidity Notice:**\n`;
      response += `• Use dehumidifiers to improve comfort\n`;
      response += `• Set AC a degree lower to compensate\n`;
      response += `• Ensure proper ventilation\n\n`;
    } else if (humidity < 30) {
      response += `🏜️ **Low Humidity Notice:**\n`;
      response += `• Use humidifiers for comfort\n`;
      response += `• Static electricity may increase\n`;
      response += `• Consider setting heat a degree lower\n\n`;
    }
    
    return response;
  }, [weatherData]);

  const botResponses = {
    greetings: [
      "🌟 Hello! I'm your SmartComfort assistant with real-time weather insights! I can help you optimize energy usage based on current conditions. What's on your mind today?",
      "👋 Hi there! I have access to live weather data and can provide personalized energy recommendations. How can I help you save energy while staying comfortable?",
      "🎯 Welcome! I'm here to help you make smart energy decisions with real-time weather context. Ask me anything about efficiency, comfort, or building performance!"
    ],
    'energy saving': [
      "⚡ **Smart Energy Strategies for Today:**\n\nBased on current conditions, here are your top energy-saving actions:\n• Adjust thermostat by 1-2 degrees for 3-5% savings\n• Use natural light to reduce lighting costs\n• Report any HVAC issues immediately\n• Optimize ventilation based on humidity levels\n\n💡 **Pro Tip:** Each degree adjustment saves approximately $15-25 per month in energy costs!",
      "🌱 **Eco-Friendly Energy Tips:**\n\n• Set smart schedules for unoccupied spaces\n• Use ceiling fans to improve comfort without changing temperature\n• Take advantage of natural ventilation when weather permits\n• Unplug electronics in unused areas\n• Use task lighting instead of overhead lights\n\n🌍 Environmental impact: These changes can reduce your carbon footprint by 10-15%!"
    ],
    'temperature': [
      () => {
        const weatherResponse = getWeatherBasedResponse();
        return weatherResponse || "🌡️ **Optimal Temperature Settings:**\n\n**Current Season Recommendations:**\n• Heating Season: 68°F (occupied), 62°F (unoccupied)\n• Cooling Season: 78°F (occupied), 82°F (unoccupied)\n\n**Smart Adjustments:**\n• Each degree saves 3-5% on energy costs\n• Use ceiling fans to feel 4°F cooler\n• Consider humidity levels for comfort\n• Personal comfort varies - dress appropriately!\n\n💰 **Cost Impact:** Proper temperature settings can save $200-400 annually per building!";
      },
      "🎯 **Precision Temperature Control:**\n\n**Real-Time Optimization:**\n• Monitor outdoor temperature changes\n• Adjust thermostats gradually (1-2 degrees)\n• Use programmable schedules\n• Consider occupancy patterns\n\n**Comfort vs Efficiency Balance:**\n• 68-70°F (winter) and 76-78°F (summer) are optimal\n• Personal fans can extend comfort range\n• Layer clothing for seasonal flexibility\n\n📊 **Data-Driven:** Buildings using smart temperature control see 15-20% energy savings!"
    ],
    'building': [
      "🏢 **Campus Building Intelligence:**\n\nI can provide insights for:\n• **Student Housing** - Valley Towers, residence halls\n• **Academic Buildings** - Sangren, Floyd Hall, Library\n• **Dining Facilities** - Valley Dining Center, Kanley\n• **Student Center** - Main hub activities\n• **Specialized Facilities** - Parkview Campus, East Campus\n\n📈 Each building has unique energy profiles. Check the Action tab for real-time performance data and personalized recommendations!",
      "🔍 **Building Performance Analysis:**\n\n**Key Metrics I Track:**\n• Real-time energy consumption\n• Efficiency ratings and trends\n• Occupancy-based optimization\n• Maintenance alerts and issues\n• Cost projections and savings\n\n**Smart Recommendations:**\n• Building-specific temperature settings\n• Peak usage optimization\n• Maintenance scheduling\n• User behavior insights\n\n🎯 Ask me about specific buildings for detailed analysis!"
    ],
    'weather': [
      () => getWeatherBasedResponse() || "🌤️ **Weather Intelligence:**\n\nI provide real-time weather-based recommendations to optimize your energy usage. Current conditions directly impact HVAC efficiency and comfort levels.",
      "🌡️ **Weather-Aware Energy Management:**\n\n**How Weather Affects Energy Use:**\n• Outdoor temperature impacts HVAC load\n• Humidity affects perceived comfort\n• Wind speed influences building envelope\n• Solar gain changes throughout the day\n\n**Smart Adjustments:**\n• Pre-cool buildings before heat waves\n• Use natural ventilation during mild weather\n• Optimize based on real-time conditions\n\n🔮 Predictive adjustments can save 10-15% on energy costs!"
    ],
    'comfort': [
      "😌 **Personal Comfort Optimization:**\n\n**Individual Comfort Factors:**\n• Temperature preferences vary by person\n• Humidity levels significantly impact comfort\n• Air quality and circulation matter\n• Personal control increases satisfaction\n\n**Smart Comfort Solutions:**\n• Layer clothing for easy adjustment\n• Use personal fans/heaters when appropriate\n• Report discomfort to facilities promptly\n• Consider desk-level climate control\n\n💡 **User Engagement:** Buildings with comfort controls see 25% higher satisfaction rates!",
      "🎨 **Comfort Design Principles:**\n\n**Environmental Comfort Elements:**\n• Temperature: 68-76°F optimal range\n• Humidity: 30-60% ideal for comfort\n• Air movement: Gentle circulation preferred\n• Lighting: Natural light enhances comfort\n\n**Behavioral Comfort Strategies:**\n• Personal comfort items (blankets, fans)\n• Flexible workspace options\n• Break areas with different climates\n• User-controlled thermostats where possible\n\n🌟 Happy occupants are more productive and energy-conscious!"
    ],
    'cost': [
      "💰 **Energy Cost Intelligence:**\n\n**Current Cost Factors:**\n• HVAC systems: 40-60% of building energy use\n• Each degree adjustment: 3-5% cost impact\n• Peak hour rates: 2-3x standard rates\n• Seasonal variations: 20-30% difference\n\n**Smart Cost Strategies:**\n• Optimize during peak pricing hours\n• Use weather-based adjustments\n• Implement smart scheduling\n• Monitor real-time consumption\n\n💵 **Potential Savings:** $500-2000 annually per building with proper optimization!",
      "📊 **Financial Impact Analysis:**\n\n**Cost Breakdown:**\n• HVAC Operations: 45% of total energy costs\n• Lighting Systems: 20% of energy costs\n• Equipment & Electronics: 15% of costs\n• Water Heating: 10% of costs\n• Other Systems: 10% of costs\n\n**ROI on Energy Efficiency:**\n• Smart thermostats: 15% ROI in 1 year\n• LED lighting: 25% ROI in 2 years\n• Building automation: 20% ROI in 3 years\n• User engagement programs: 30% ROI in 6 months\n\n🎯 Focus on high-impact, low-cost solutions first!"
    ],
    'default': [
      "🤔 **Great Question!** While I specialize in energy efficiency, comfort optimization, and weather-based recommendations, I'm always learning to help you better. Try asking me about:\n\n⚡ Energy-saving strategies\n🌡️ Temperature optimization\n🌤️ Current weather impact\n🏢 Building performance\n💰 Cost reduction\n😌 Personal comfort\n\nWhat specific aspect interests you most?",
      "🎯 **I'm Here to Help!** I can provide insights on energy efficiency, comfort optimization, weather-based recommendations, and building performance. My knowledge includes real-time weather data and smart energy strategies.\n\n**Popular Topics:**\n• Weather-based energy tips\n• Building-specific recommendations\n• Cost-saving strategies\n• Comfort optimization\n• Environmental impact\n\nWhat would you like to explore today?"
    ]
  };

  const getBotResponse = useCallback((userInput) => {
    const input = userInput.toLowerCase();
    
    // Check for weather-related queries first
    if (input.includes('weather') || input.includes('current') || input.includes('outside') || input.includes('temperature outside')) {
      const weatherResponse = botResponses.weather[Math.floor(Math.random() * botResponses.weather.length)];
      return typeof weatherResponse === 'function' ? weatherResponse() : weatherResponse;
    }
    
    // Check for greetings
    if (input.includes('hi') || input.includes('hello') || input.includes('hey') || input.includes('good morning') || input.includes('good afternoon')) {
      return botResponses.greetings[Math.floor(Math.random() * botResponses.greetings.length)];
    }
    
    // Check for energy-related queries
    if (input.includes('energy') || input.includes('save') || input.includes('efficiency') || input.includes('reduce') || input.includes('conserve')) {
      return botResponses['energy saving'][Math.floor(Math.random() * botResponses['energy saving'].length)];
    }
    
    // Check for temperature queries
    if (input.includes('temperature') || input.includes('temp') || input.includes('thermostat') || input.includes('heating') || input.includes('cooling') || input.includes('ac') || input.includes('air conditioning')) {
      const tempResponse = botResponses.temperature[Math.floor(Math.random() * botResponses.temperature.length)];
      return typeof tempResponse === 'function' ? tempResponse() : tempResponse;
    }
    
    // Check for building queries
    if (input.includes('building') || input.includes('campus') || input.includes('dorm') || input.includes('library') || input.includes('dining') || input.includes('housing')) {
      return botResponses.building[Math.floor(Math.random() * botResponses.building.length)];
    }
    
    // Check for comfort queries
    if (input.includes('comfort') || input.includes('comfortable') || input.includes('how to feel') || input.includes('too hot') || input.includes('too cold')) {
      return botResponses.comfort[Math.floor(Math.random() * botResponses.comfort.length)];
    }
    
    // Check for cost queries
    if (input.includes('cost') || input.includes('money') || input.includes('price') || input.includes('bill') || input.includes('savings') || input.includes('budget')) {
      return botResponses.cost[Math.floor(Math.random() * botResponses.cost.length)];
    }
    
    // Default response
    return botResponses.default[Math.floor(Math.random() * botResponses.default.length)];
  }, [botResponses]);

  const handleSendMessage = () => {
    if (inputText.trim() === '') return;

    const userMessage = {
      id: messages.length + 1,
      type: 'user',
      text: inputText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsTyping(true);

    // Simulate bot response delay
    setTimeout(() => {
      const botMessage = {
        id: messages.length + 2,
        type: 'bot',
        text: getBotResponse(inputText),
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMessage]);
      setIsTyping(false);
    }, 1500);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const quickActions = [
    { icon: Cloud, text: 'Current Weather', query: 'weather' },
    { icon: Zap, text: 'Energy Saving Tips', query: 'energy saving tips' },
    { icon: Thermometer, text: 'Temperature Advice', query: 'optimal temperature' },
    { icon: Leaf, text: 'Eco-Friendly', query: 'environmental impact' },
    { icon: TrendingDown, text: 'Cost Reduction', query: 'reduce energy costs' },
    { icon: Lightbulb, text: 'Smart Tips', query: 'smart energy habits' }
  ];

  const QuickAction = ({ icon: Icon, text, query }) => (
    <button
      onClick={() => {
        setInputText(query);
        handleSendMessage();
      }}
      className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-gray-50 to-gray-100 hover:from-gray-100 hover:to-gray-200 rounded-lg transition-all duration-200 text-sm border border-gray-200 hover:border-gray-300 shadow-sm hover:shadow-md"
    >
      <Icon className="h-4 w-4 text-gray-600" />
      <span className="text-gray-700 font-medium">{text}</span>
    </button>
  );

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-12rem)]">
      {/* Header */}
      <div className="bg-gradient-to-r from-green-600 to-teal-600 rounded-t-2xl p-6 text-white shadow-lg">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <MessageCircle className="h-8 w-8 animate-pulse" />
            <div>
              <h1 className="text-2xl font-bold">SmartComfort Assistant</h1>
              <p className="text-green-100">AI-powered energy efficiency with real-time weather data</p>
            </div>
          </div>
          {weatherData && (
            <div className="text-right">
              <div className="flex items-center gap-2 text-white">
                <Sun className="h-5 w-5" />
                <span className="text-lg font-semibold">{weatherData.temp}°F</span>
              </div>
              <p className="text-green-100 text-sm">{weatherData.description}</p>
            </div>
          )}
        </div>
      </div>

      {/* Chat Container */}
      <div className="bg-white border-x border-gray-200 h-[calc(100%-8rem)] flex flex-col shadow-lg">
        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gradient-to-b from-gray-50 to-white">
          {messages.map((message) => (
            <div
              key={message.id}
              className={`flex gap-3 ${message.type === 'user' ? 'justify-end' : 'justify-start'} animate-fadeIn`}
            >
              {message.type === 'bot' && (
                <div className="w-10 h-10 bg-gradient-to-br from-green-100 to-green-200 rounded-full flex items-center justify-center flex-shrink-0 shadow-md">
                  <Bot className="h-6 w-6 text-green-600" />
                </div>
              )}
              
              <div
                className={`max-w-[75%] px-4 py-3 rounded-2xl shadow-md ${
                  message.type === 'user'
                    ? 'bg-gradient-to-br from-blue-600 to-blue-700 text-white'
                    : 'bg-gradient-to-br from-gray-50 to-gray-100 text-gray-800 border border-gray-200'
                }`}
              >
                <div className="whitespace-pre-line text-sm leading-relaxed">{message.text}</div>
                <p className={`text-xs mt-2 font-medium ${
                  message.type === 'user' ? 'text-blue-100' : 'text-gray-500'
                }`}>
                  {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>

              {message.type === 'user' && (
                <div className="w-10 h-10 bg-gradient-to-br from-blue-100 to-blue-200 rounded-full flex items-center justify-center flex-shrink-0 shadow-md">
                  <User className="h-6 w-6 text-blue-600" />
                </div>
              )}
            </div>
          ))}

          {isTyping && (
            <div className="flex gap-3 justify-start">
              <div className="w-10 h-10 bg-gradient-to-br from-green-100 to-green-200 rounded-full flex items-center justify-center shadow-md">
                <Bot className="h-6 w-6 text-green-600 animate-pulse" />
              </div>
              <div className="bg-gradient-to-br from-gray-50 to-gray-100 px-4 py-3 rounded-2xl shadow-md border border-gray-200">
                <div className="flex gap-1 items-center">
                  <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                  <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <span className="text-xs text-gray-500 ml-2">Thinking...</span>
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Quick Actions */}
        <div className="p-4 border-t border-gray-200 bg-gradient-to-b from-white to-gray-50">
          <div className="mb-3">
            <p className="text-xs text-gray-500 font-medium mb-2">Quick Actions:</p>
            <div className="flex flex-wrap gap-2">
              {quickActions.map((action, index) => (
                <QuickAction key={index} {...action} />
              ))}
            </div>
          </div>
        </div>

        {/* Input */}
        <div className="p-4 border-t border-gray-200 bg-gradient-to-b from-gray-50 to-gray-100">
          <div className="flex gap-3">
            <input
              type="text"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Ask me about weather, energy saving, temperature settings, or building efficiency..."
              className="flex-1 px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent bg-white shadow-sm transition-all duration-200"
              disabled={isTyping}
            />
            <button
              onClick={handleSendMessage}
              disabled={isTyping || inputText.trim() === ''}
              className="bg-gradient-to-r from-green-600 to-green-700 text-white p-3 rounded-lg hover:from-green-700 hover:to-green-800 transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:shadow-lg transform hover:scale-105"
            >
              <Send className="h-5 w-5" />
            </button>
          </div>
          <div className="flex items-center gap-2 mt-2 text-xs text-gray-500">
            <Zap className="h-3 w-3" />
            <span>Powered by AI with real-time weather data</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatBot;
